            className="w-full pl-10 pr-3 py-3 bg-white dark:bg-slate-950 border border-gray-100 dark:border-slate-800 rounded-xl text-xs font-medium text-slate-700 dark:text-slate-200 placeholder-gray-400 outline-none focus:border-indigo-500 focus:ring-4 focus:ring-indigo-500/10 transition-all shadow-depth-sm hover:shadow-depth-md dark:shadow-[inset_0_1px_1px_rgba(255,255,255,0.05)]"
        />
    </div>
);

export const Modal = ({ isOpen, title, onClose, children }: any) => {
    if (!isOpen) return null;
    return (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-[300] flex items-center justify-center p-4 animate-in fade-in duration-300" onClick={onClose}>
            <div className="bg-white/95 dark:bg-slate-900/95 w-full max-w-lg rounded-[2rem] shadow-3d-lift border border-white/20 dark:border-slate-700/50 transform transition-all animate-zoom-in-spring duration-500 overflow-hidden" onClick={e => e.stopPropagation()}>
                <div className="flex justify-between items-center p-6 border-b border-gray-100 dark:border-slate-800 bg-gray-50/50 dark:bg-slate-900/50 backdrop-blur-md">
                    <h3 className="text-xl font-black text-slate-900 dark:text-white tracking-tight leading-none">{title}</h3>
                    <button onClick={onClose} className="p-2 rounded-full hover:bg-red-50 hover:text-red-500 dark:hover:bg-red-900/20 transition-all duration-300 text-slate-400 hover:rotate-90">
                        <Icon name="X" size={22} />
                    </button>
                </div>
                <div className="p-8 max-h-[75vh] overflow-y-auto custom-scrollbar bg-white/50 dark:bg-slate-900/50">
                    {children}
                </div>
            </div>
        </div>
    );
};

export const Toast = ({ message, onClose }: { message: string, onClose: () => void }) => {
    const [isExiting, setIsExiting] = useState(false);
    const [isMounted, setIsMounted] = useState(false);

    const handleClose = () => {
        setIsExiting(true);
        setTimeout(() => onClose(), 400); 
    };

    useEffect(() => {
        setIsMounted(true);
        const timer = setTimeout(handleClose, 4500);
        return () => clearTimeout(timer);
    }, [onClose]);

    return (
        <div className={`fixed z-[9999] top-10 left-1/2 -translate-x-1/2 transition-all duration-500 ease-spring ${!isMounted ? 'opacity-0 -translate-y-10' : isExiting ? 'opacity-0 scale-95 -translate-y-10' : 'opacity-100 scale-100 translate-y-0'}`}>
            <div className="bg-slate-900/90 dark:bg-white/90 backdrop-blur-xl text-white dark:text-slate-900 px-6 py-4 rounded-2xl shadow-3d-lift flex items-center gap-4 border border-white/10 dark:border-slate-200/20">
                <div className="flex-shrink-0 p-2 bg-emerald-500 rounded-full text-white shadow-neon-emerald">
                    <Icon name="CheckLineart" size={18}/>
                </div>
                <div className="flex-1 min-w-0">
                    <span className="text-[10px] font-black uppercase tracking-widest opacity-60 block mb-0.5">Notification</span>
                    <span className="text-sm font-bold leading-snug">{message}</span>
                </div>
                <button onClick={handleClose} className="ml-2 p-1 text-slate-400 hover:text-white dark:hover:text-slate-900 transition-colors">
                    <Icon name="X" size={18}/>
                </button>
            </div>
        </div>
    );
};

import React, { useState, useRef } from 'react';
import { Icon } from '../UI';
import { Standard, Clause, Group } from '../../types';
import { useDebounce, copyToClipboard } from '../../utils';

interface StandardExplorerProps {
    standard: Standard | undefined;
    standardKey: string;
    selectedClauses: string[];
    setSelectedClauses: React.Dispatch<React.SetStateAction<string[]>>;
    onReferenceClause: (clause: Clause) => void;
    repairedIds: string[];
    onScrollTrigger?: () => void;
}

export const StandardExplorer: React.FC<StandardExplorerProps> = ({
    standard, standardKey, selectedClauses, setSelectedClauses, onReferenceClause, repairedIds, onScrollTrigger
}) => {
    const [searchQueryRaw, setSearchQueryRaw] = useState("");
    const [expandedGroups, setExpandedGroups] = useState<string[]>([]);
    const [expandedClauses, setExpandedClauses] = useState<string[]>([]);
    const [copiedClauseId, setCopiedClauseId] = useState<string | null>(null);

    const searchQuery = useDebounce(searchQueryRaw, 300);
    const scrollContainerRef = useRef<HTMLDivElement>(null);

    const toggleGroupExpand = (id: string) => setExpandedGroups(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
    const toggleClauseExpand = (id: string) => setExpandedClauses(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);

    const allGroupIds = standard?.groups.map(g => g.id) || [];
    const areAllGroupsExpanded = allGroupIds.length > 0 && expandedGroups.length === allGroupIds.length;

    const toggleExpandAll = () => {
        setExpandedGroups(areAllGroupsExpanded ? [] : allGroupIds);
    };

    const handleCopySelectedClauses = () => {
        if (!standard) return;
        const findClause = (id: string, list: Clause[]): Clause | undefined => {
            for (let c of list) { 
                if (c.id === id) return c; 
                if (c.subClauses) { 
                    const f = findClause(id, c.subClauses); 
                    if (f) return f; 
                } 
            }
        };
        const allClauses = standard.groups.flatMap(g => g.clauses);
        const selectedData = selectedClauses
            .map(id => findClause(id, allClauses))
            .filter((c): c is Clause => !!c)
            .map(c => `[${c.code}] ${c.title}`)
            .join('\n');
        copyToClipboard(selectedData);
    };

    const handleSingleClauseCopy = (e: React.MouseEvent, c: Clause) => {
        e.stopPropagation();
        copyToClipboard(`[${c.code}] ${c.title}`);
        setCopiedClauseId(c.id);
        setTimeout(() => setCopiedClauseId(null), 1500);
    };

    const toggleClauseSelection = (clause: Clause) => {
        const getAllIds = (c: Clause): string[] => {
            let ids = [c.id];
            if (c.subClauses) c.subClauses.forEach(sub => ids.push(...getAllIds(sub)));
            return ids;
        };
        const targetIds = getAllIds(clause);
        const allSelected = targetIds.every(id => selectedClauses.includes(id));
        setSelectedClauses(prev => allSelected ? prev.filter(id => !targetIds.includes(id)) : Array.from(new Set([...prev, ...targetIds])));
    };

    const toggleGroupSelection = (group: Group) => {
        const getAllIds = (list: Clause[]): string[] => {
            let ids: string[] = [];
            list.forEach(c => {
                ids.push(c.id);
                if (c.subClauses) ids.push(...getAllIds(c.subClauses));
            });
            return ids;
        };
        const groupIds = getAllIds(group.clauses);
        const allSelected = groupIds.every(id => selectedClauses.includes(id));

        if (allSelected) {
            setSelectedClauses(prev => prev.filter(id => !groupIds.includes(id)));
        } else {
            setSelectedClauses(prev => [...new Set([...prev, ...groupIds])]);
        }
    };

    const renderClauseItem = (c: Clause, level: number = 0) => {
        const hasSubs = c.subClauses && c.subClauses.length > 0;
        const isExpanded = expandedClauses.includes(c.id) || !!searchQuery;
        const isSelected = selectedClauses.includes(c.id);
        const isRepaired = repairedIds.includes(c.id);

        const getSelectionStatus = (item: Clause): { all: boolean, some: boolean } => {
            if (!item.subClauses) return { all: selectedClauses.includes(item.id), some: selectedClauses.includes(item.id) };
            const subRes = item.subClauses.map(getSelectionStatus);
            const all = selectedClauses.includes(item.id) && subRes.every(r => r.all);
            const some = selectedClauses.includes(item.id) || subRes.some(r => r.some);
            return { all, some };
        };
        const selection = getSelectionStatus(c);

        return (
            <div key={c.id} className={`flex flex-col transition-all duration-300 ${level > 0 ? 'ml-4 border-l-2 border-slate-200 dark:border-slate-800' : ''}`}>
                <div 
                    className={`group flex items-start gap-3 p-3 rounded-2xl transition-all duration-300 transform cursor-pointer ${
                        isSelected 
                            ? 'bg-indigo-50/80 dark:bg-indigo-500/10 shadow-depth-sm translate-x-1 border border-indigo-200 dark:border-indigo-500/30' 
                            : 'hover:bg-white dark:hover:bg-slate-800/80 hover:shadow-depth-md hover:-translate-y-0.5 hover:translate-x-1 border border-transparent'
                    }`}
                    onClick={() => hasSubs ? toggleClauseExpand(c.id) : toggleClauseSelection(c)}
                >
                    <button 
                        onClick={(e) => { e.stopPropagation(); toggleClauseSelection(c); }} 
                        className={`mt-1 flex-shrink-0 transition-all duration-300 ${selection.some ? 'text-indigo-600 dark:text-indigo-400 scale-110' : 'text-slate-300 dark:text-slate-600 hover:text-slate-400'}`}
                    >
                        {selection.all ? <Icon name="CheckSquare" size={18}/> : selection.some ? <div className="w-4 h-4 bg-indigo-500 rounded flex items-center justify-center shadow-neon-blue"><div className="w-2.5 h-0.5 bg-white"></div></div> : <Icon name="Square" size={18}/>}
                    </button>

                    <div className="flex-1 min-w-0">
                        <div className="flex items-start justify-between gap-2">
                            <div className="flex items-center gap-2 flex-wrap">
                                <span className="text-[10px] font-black text-indigo-700 dark:text-indigo-300 uppercase tracking-widest bg-indigo-100/50 dark:bg-indigo-900/40 px-2 py-0.5 rounded-lg border border-indigo-200/50 dark:border-indigo-800/50">{c.code}</span>
                                <span className="text-sm font-bold text-slate-800 dark:text-slate-100 group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors leading-snug">{c.title}</span>
                                {isRepaired && <span className="text-[8px] font-black bg-emerald-500 text-white px-1.5 py-0.5 rounded shadow-neon-emerald animate-pulse">FIXED</span>}
                            </div>
                            <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-all">
                                <button onClick={(e) => { e.stopPropagation(); onReferenceClause(c); }} className="p-1.5 hover:bg-indigo-50 dark:hover:bg-indigo-900/40 rounded-lg text-slate-400 hover:text-indigo-600 transition-all">
                                    <Icon name="BookOpen" size={14} />
                                </button>
                                <button onClick={(e) => handleSingleClauseCopy(e, c)} className="p-1.5 hover:bg-indigo-50 dark:hover:bg-indigo-900/40 rounded-lg text-slate-400 hover:text-indigo-600 transition-all">
                                    <Icon name={copiedClauseId === c.id ? "CheckThick" : "Copy"} size={14} className={copiedClauseId === c.id ? "text-emerald-500" : ""} />
                                </button>
                            </div>
                        </div>
                        <p className="text-[11px] text-slate-500 dark:text-slate-400 mt-2 line-clamp-2 leading-relaxed font-medium">
                            {c.description}
                        </p>
                    </div>
                </div>

                <div className={`grid transition-all duration-300 ease-in-out ${hasSubs && isExpanded ? 'grid-rows-[1fr] opacity-100 mt-1' : 'grid-rows-[0fr] opacity-0'}`}>
                    <div className="overflow-hidden">
                        {hasSubs && <div className="flex flex-col gap-1">{c.subClauses!.map(sub => renderClauseItem(sub, level + 1))}</div>}
                    </div>
                </div>
            </div>
        );
    };

    const getGroupStyles = (title: string) => {
        const t = title.toUpperCase();
        if (t.includes('PLAN')) return 'from-blue-500 to-blue-700 shadow-blue-500/20';
        if (t.includes('SUPPORT')) return 'from-purple-500 to-purple-700 shadow-purple-500/20';
        if (t.includes('DO')) return 'from-orange-500 to-orange-700 shadow-orange-500/20';
        if (t.includes('CHECK') || t.includes('ACT')) return 'from-emerald-500 to-emerald-700 shadow-emerald-500/20';
        if (t.includes('ANNEX')) return 'from-rose-500 to-rose-700 shadow-rose-500/20';
        return 'from-slate-600 to-slate-800 shadow-slate-500/20';
    };

    return (
        <div className="flex-1 flex flex-col min-h-0 bg-slate-50/30 dark:bg-slate-950/30 backdrop-blur-sm">
            <div className="p-4 bg-white/80 dark:bg-slate-900/80 border-b border-slate-200 dark:border-slate-800 shadow-depth-sm z-10 shrink-0 sticky top-0 backdrop-blur-xl">
                <div className="flex items-center gap-3">
                    <div className="relative flex-1 group">
                        <Icon name="Search" size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-indigo-500 transition-colors" />
                        <input 
                            className="w-full bg-slate-100 dark:bg-slate-950/50 py-2.5 pl-10 pr-4 rounded-xl text-xs font-bold outline-none border border-transparent focus:border-indigo-500/30 focus:bg-white dark:focus:bg-slate-900 transition-all shadow-inner"
                            placeholder="Find clauses..."
                            value={searchQueryRaw}
                            onChange={e => setSearchQueryRaw(e.target.value)}
                        />
                    </div>

                    <button 
                        onClick={toggleExpandAll} 
                        className="p-2.5 rounded-xl bg-slate-100 dark:bg-slate-800 text-slate-500 hover:text-indigo-600 transition-all shadow-depth-sm active:scale-90"
                        title={areAllGroupsExpanded ? "Collapse All" : "Expand All"}
                    >
                        <Icon name={areAllGroupsExpanded ? "CollapsePanel" : "ExpandPanel"} size={16}/>
                    </button>

                    {selectedClauses.length > 0 && (
                        <div className="flex gap-2 animate-in slide-in-from-right duration-300">
                            <button onClick={handleCopySelectedClauses} className="p-2.5 rounded-xl bg-indigo-100 dark:bg-indigo-900/50 text-indigo-700 dark:text-indigo-300 border border-indigo-200 dark:border-indigo-800 shadow-depth-sm hover:-translate-y-0.5 transition-all">
                                <Icon name="Copy" size={16} />
                            </button>
                            <button onClick={() => setSelectedClauses([])} className="relative p-2.5 rounded-xl bg-red-100 dark:bg-red-900/50 text-red-700 dark:text-red-400 border border-red-200 dark:border-red-800 shadow-depth-sm hover:-translate-y-0.5 transition-all">
                                <Icon name="Trash2" size={16} />
                                <span className="absolute -top-1.5 -right-1.5 w-5 h-5 bg-red-600 text-white text-[10px] font-black rounded-full flex items-center justify-center border-2 border-white dark:border-slate-900 shadow-lg">{selectedClauses.length}</span>
                            </button>
                        </div>
                    )}
                </div>
            </div>

            <div 
                ref={scrollContainerRef}
                className="flex-1 overflow-y-auto custom-scrollbar p-4 scroll-smooth"
                onScroll={(e) => {
                    if (e.currentTarget.scrollTop > 50 && onScrollTrigger) onScrollTrigger();
                }}
            >
                <div className="space-y-6 pb-20">
                    {!standard ? (
                        <div className="flex flex-col items-center justify-center py-20 opacity-30">
                            <Icon name="Book" size={48} className="mb-4" />
                            <p className="text-sm font-black uppercase tracking-widest">Select standard to explore</p>
                        </div>
                    ) : (
                        standard.groups.map(g => {
                            const isGroupExpanded = expandedGroups.includes(g.id) || !!searchQuery;
                            const matchesSearch = (c: Clause): boolean => {
                                const term = searchQuery.toLowerCase();
                                return c.code.toLowerCase().includes(term) || c.title.toLowerCase().includes(term) || (c.subClauses ? c.subClauses.some(matchesSearch) : false);
                            };
                            const filteredClauses = searchQuery ? g.clauses.filter(matchesSearch) : g.clauses;
                            if (filteredClauses.length === 0) return null;

                            return (
                                <div key={g.id} className="bg-white/40 dark:bg-slate-900/40 rounded-3xl border border-white/20 dark:border-slate-800/50 shadow-depth-md overflow-hidden transition-all duration-500 hover:shadow-depth-lg group/group">
                                    <div 
                                        className="flex items-center justify-between p-4 cursor-pointer hover:bg-white/60 dark:hover:bg-slate-800/60 transition-colors"
                                        onClick={() => toggleGroupExpand(g.id)}
                                    >
                                        <div className="flex items-center gap-4">
                                            <div 
                                                onClick={(e) => { e.stopPropagation(); toggleGroupSelection(g); }}
                                                className={`w-10 h-10 rounded-2xl flex items-center justify-center text-white bg-gradient-to-br shadow-lg transform transition-all group-hover/group:scale-110 active:scale-95 ${getGroupStyles(g.title)}`}
                                            >
                                                <Icon name={g.icon} size={18}/>
                                            </div>
                                            <div>
                                                <h4 className="text-xs font-black text-slate-900 dark:text-white uppercase tracking-widest leading-none mb-1">{g.title}</h4>
                                                <p className="text-[10px] text-slate-400 font-bold">{filteredClauses.length} Main Clauses</p>
                                            </div>
                                        </div>
                                        <div className={`w-8 h-8 rounded-full flex items-center justify-center transition-all ${isGroupExpanded ? 'bg-indigo-50 dark:bg-indigo-900/30 text-indigo-600 rotate-180' : 'text-slate-400'}`}>
                                            <Icon name="ChevronDown" size={14} />
                                        </div>
                                    </div>

                                    <div className={`grid transition-all duration-500 ease-in-out ${isGroupExpanded ? 'grid-rows-[1fr] opacity-100' : 'grid-rows-[0fr] opacity-0'}`}>
                                        <div className="overflow-hidden">
                                            <div className="p-3 flex flex-col gap-1.5 border-t border-slate-100 dark:border-slate-800/50">
                                                {filteredClauses.map(c => renderClauseItem(c))}
                                            </div>
                                        </div>
                                    </div>
                                </div>
                            );
                        })
                    )}
                </div>
            </div>
        </div>
    );
};

import React, { useRef, useEffect } from 'react';
import { Icon } from '../UI';
import { AnalysisResult, FindingStatus, FindingsViewMode } from '../../types';

interface FindingsViewProps {
    analysisResult: AnalysisResult[] | null;
    setAnalysisResult: React.Dispatch<React.SetStateAction<AnalysisResult[] | null>>;
    selectedFindings: Record<string, boolean>;
    setSelectedFindings: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
    isAnalyzeLoading: boolean;
    loadingMessage: string;
    currentAnalyzingClause: string;
    viewMode: FindingsViewMode;
    setViewMode: (mode: FindingsViewMode) => void;
    focusedFindingIndex: number;
    setFocusedFindingIndex: (index: number) => void;
    onExport: (type: 'notes', lang: 'en' | 'vi') => void;
    notesLanguage: 'en' | 'vi';
    setNotesLanguage: (lang: 'en' | 'vi') => void;
}

export const FindingsView: React.FC<FindingsViewProps> = ({
    analysisResult, setAnalysisResult, selectedFindings, setSelectedFindings,
    isAnalyzeLoading, loadingMessage, currentAnalyzingClause,
    viewMode, setViewMode, focusedFindingIndex, setFocusedFindingIndex,
    onExport, notesLanguage, setNotesLanguage
}) => {
    const findingsContainerRef = useRef<HTMLDivElement>(null);
    const findingRefs = useRef<(HTMLDivElement | null)[]>([]);

    useEffect(() => {
        if (viewMode === 'list' && findingsContainerRef.current) {
            findingsContainerRef.current.scrollTop = findingsContainerRef.current.scrollHeight;
        }
    }, [analysisResult?.length, viewMode]);

    const handleUpdateFinding = (index: number, field: keyof AnalysisResult, value: string) => {
        setAnalysisResult(prev => {
            if (!prev) return null;
            const newArr = [...prev];
            newArr[index] = { ...newArr[index], [field]: value };
            return newArr;
        });
    };

    const getStatusConfig = (status: FindingStatus) => {
        switch (status) {
            case 'COMPLIANT': return { label: 'Compliant', color: 'text-emerald-600 dark:text-emerald-400', bg: 'bg-emerald-50 dark:bg-emerald-900/30', border: 'border-emerald-200 dark:border-emerald-800/50', dot: 'bg-emerald-500 shadow-neon-emerald' };
            case 'NC_MAJOR': return { label: 'NC Major', color: 'text-red-600 dark:text-red-400', bg: 'bg-red-50 dark:bg-red-900/30', border: 'border-red-200 dark:border-red-800/50', dot: 'bg-red-600 shadow-[0_0_10px_rgba(220,38,38,0.5)]' };
            case 'NC_MINOR': return { label: 'NC Minor', color: 'text-orange-600 dark:text-orange-400', bg: 'bg-orange-50 dark:bg-orange-900/30', border: 'border-orange-200 dark:border-orange-800/50', dot: 'bg-orange-500 shadow-[0_0_10px_rgba(245,158,11,0.5)]' };
            case 'OFI': return { label: 'Opportunity', color: 'text-blue-600 dark:text-blue-400', bg: 'bg-blue-50 dark:bg-blue-900/30', border: 'border-blue-200 dark:border-blue-800/50', dot: 'bg-blue-500 shadow-neon-blue' };
            default: return { label: 'N/A', color: 'text-slate-500', bg: 'bg-slate-100 dark:bg-slate-800', border: 'border-slate-200 dark:border-slate-700', dot: 'bg-slate-400' };
        }
    };

    const renderFindingCard = (res: AnalysisResult, idx: number) => {
        const config = getStatusConfig(res.status as FindingStatus);
        const isSelected = selectedFindings[res.clauseId];

        return (
            <div
                key={idx}
                ref={el => { findingRefs.current[idx] = el; }}
                className={`group relative bg-white dark:bg-slate-900 rounded-[2rem] p-6 border transition-all duration-500 hover:-translate-y-1 hover:shadow-3d-lift ${
                    isSelected 
                        ? 'border-indigo-400 dark:border-indigo-600 shadow-depth-lg ring-1 ring-indigo-500/20' 
                        : 'border-slate-100 dark:border-slate-800/50 shadow-depth-md'
                }`}
                onClick={() => setSelectedFindings(prev => ({ ...prev, [res.clauseId]: !prev[res.clauseId] }))}
            >
                {/* Status Indicator Bar */}
                <div className={`absolute top-0 left-12 right-12 h-1 rounded-b-full ${config.dot}`}></div>

                <div className="flex flex-col gap-4">
