import React, { useState, useRef } from 'react';
import { Icon } from '../UI';
import { Standard, Clause, Group } from '../../types';
import { useDebounce, copyToClipboard } from '../../utils';

interface StandardExplorerProps {
    standard: Standard | undefined;
    standardKey: string;
    selectedClauses: string[];
    setSelectedClauses: React.Dispatch<React.SetStateAction<string[]>>;
    onReferenceClause: (clause: Clause) => void;
    repairedIds: string[];
    onScrollTrigger?: () => void;
}

export const StandardExplorer: React.FC<StandardExplorerProps> = ({
    standard, standardKey, selectedClauses, setSelectedClauses, onReferenceClause, repairedIds, onScrollTrigger
}) => {
    const [searchQueryRaw, setSearchQueryRaw] = useState("");
    const [expandedGroups, setExpandedGroups] = useState<string[]>([]);
    const [expandedClauses, setExpandedClauses] = useState<string[]>([]);
    const [copiedClauseId, setCopiedClauseId] = useState<string | null>(null);

    const searchQuery = useDebounce(searchQueryRaw, 300);
    const scrollContainerRef = useRef<HTMLDivElement>(null);

    const toggleGroupExpand = (id: string) => setExpandedGroups(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);
    const toggleClauseExpand = (id: string) => setExpandedClauses(prev => prev.includes(id) ? prev.filter(x => x !== id) : [...prev, id]);

    const allGroupIds = standard?.groups.map(g => g.id) || [];
    const areAllGroupsExpanded = allGroupIds.length > 0 && expandedGroups.length === allGroupIds.length;

    const toggleExpandAll = () => {
        setExpandedGroups(areAllGroupsExpanded ? [] : allGroupIds);
    };

    const handleCopySelectedClauses = () => {
        if (!standard) return;
        const findClause = (id: string, list: Clause[]): Clause | undefined => {
            for (let c of list) { 
                if (c.id === id) return c; 
                if (c.subClauses) { 
                    const f = findClause(id, c.subClauses); 
                    if (f) return f; 
                } 
            }
        };
        const allClauses = standard.groups.flatMap(g => g.clauses);
        const selectedData = selectedClauses
            .map(id => findClause(id, allClauses))
            .filter((c): c is Clause => !!c)
            .map(c => `[${c.code}] ${c.title}`)
            .join('\n');
        copyToClipboard(selectedData);
    };

    const handleSingleClauseCopy = (e: React.MouseEvent, c: Clause) => {
        e.stopPropagation();
        copyToClipboard(`[${c.code}] ${c.title}`);
        setCopiedClauseId(c.id);
        setTimeout(() => setCopiedClauseId(null), 1500);
    };

    const toggleClauseSelection = (clause: Clause) => {
        const getAllIds = (c: Clause): string[] => {
            let ids = [c.id];
            if (c.subClauses) c.subClauses.forEach(sub => ids.push(...getAllIds(sub)));
            return ids;
        };
        const targetIds = getAllIds(clause);
        const allSelected = targetIds.every(id => selectedClauses.includes(id));
        setSelectedClauses(prev => allSelected ? prev.filter(id => !targetIds.includes(id)) : Array.from(new Set([...prev, ...targetIds])));
    };

    const toggleGroupSelection = (group: Group) => {
        const getAllIds = (list: Clause[]): string[] => {
            let ids: string[] = [];
            list.forEach(c => {
                ids.push(c.id);
                if (c.subClauses) ids.push(...getAllIds(c.subClauses));
            });
            return ids;
        };
        const groupIds = getAllIds(group.clauses);
        const allSelected = groupIds.every(id => selectedClauses.includes(id));

        if (allSelected) {
            setSelectedClauses(prev => prev.filter(id => !groupIds.includes(id)));
        } else {
            setSelectedClauses(prev => [...new Set([...prev, ...groupIds])]);
        }
    };

    const renderClauseItem = (c: Clause, level: number = 0) => {
        const hasSubs = c.subClauses && c.subClauses.length > 0;
        const isExpanded = expandedClauses.includes(c.id) || !!searchQuery;
        const isSelected = selectedClauses.includes(c.id);
        const isRepaired = repairedIds.includes(c.id);

        const getSelectionStatus = (item: Clause): { all: boolean, some: boolean } => {
            if (!item.subClauses) return { all: selectedClauses.includes(item.id), some: selectedClauses.includes(item.id) };
            const subRes = item.subClauses.map(getSelectionStatus);
            const all = selectedClauses.includes(item.id) && subRes.every(r => r.all);
            const some = selectedClauses.includes(item.id) || subRes.some(r => r.some);
            return { all, some };
        };
        const selection = getSelectionStatus(c);

        return (
            <div key={c.id} className={`flex flex-col ${level > 0 ? 'ml-4 border-l-2 border-slate-200 dark:border-slate-800' : ''}`}>
                <div 
                    className={`group flex items-start gap-3 p-3 rounded-2xl transition-all cursor-pointer ${
                        isSelected 
                            ? 'bg-indigo-50 dark:bg-indigo-900/20' 
                            : 'hover:bg-gray-50 dark:hover:bg-slate-800'
                    }`}
                    onClick={() => hasSubs ? toggleClauseExpand(c.id) : toggleClauseSelection(c)}
                >
                    <button 
                        onClick={(e) => { e.stopPropagation(); toggleClauseSelection(c); }} 
                        className={`mt-1 flex-shrink-0 transition-colors ${selection.some ? 'text-indigo-600 dark:text-indigo-400' : 'text-slate-300 dark:text-slate-600 hover:text-slate-400'}`}
                    >
                        {selection.all ? <Icon name="CheckSquare" size={18}/> : selection.some ? <div className="w-4 h-4 bg-indigo-500 rounded flex items-center justify-center"><div className="w-2.5 h-0.5 bg-white"></div></div> : <Icon name="Square" size={18}/>}
                    </button>

                    <div className="flex-1 min-w-0">
                        <div className="flex items-start justify-between gap-2">
                            <div className="flex items-center gap-2 flex-wrap">
                                <span className="text-[10px] font-black text-indigo-700 dark:text-indigo-300 uppercase tracking-widest bg-indigo-100/50 dark:bg-indigo-900/40 px-2 py-0.5 rounded-lg">{c.code}</span>
                                <span className="text-sm font-bold text-slate-800 dark:text-slate-100 group-hover:text-indigo-600 dark:group-hover:text-indigo-400 transition-colors leading-snug">{c.title}</span>
                                {isRepaired && <span className="text-[8px] font-black bg-emerald-500 text-white px-1.5 py-0.5 rounded">FIXED</span>}
                            </div>
                            <div className="flex items-center gap-1 opacity-0 group-hover:opacity-100 transition-all">
                                <button onClick={(e) => { e.stopPropagation(); onReferenceClause(c); }} className="p-1.5 hover:bg-gray-200 dark:hover:bg-slate-700 rounded-lg text-slate-400 hover:text-indigo-600 transition-all">
                                    <Icon name="BookOpen" size={14} />
                                </button>
                                <button onClick={(e) => handleSingleClauseCopy(e, c)} className="p-1.5 hover:bg-gray-200 dark:hover:bg-slate-700 rounded-lg text-slate-400 hover:text-indigo-600 transition-all">
                                    <Icon name={copiedClauseId === c.id ? "CheckThick" : "Copy"} size={14} className={copiedClauseId === c.id ? "text-emerald-500" : ""} />
                                </button>
                            </div>
                        </div>
                        <p className="text-[11px] text-slate-500 dark:text-slate-400 mt-1 line-clamp-2 leading-relaxed">
                            {c.description}
                        </p>
                    </div>
                </div>
                {hasSubs && isExpanded && (
                    <div className="flex flex-col gap-1">{c.subClauses!.map(sub => renderClauseItem(sub, level + 1))}</div>
                )}
            </div>
        );
    };

    const getGroupStyles = (title: string) => {
        const t = title.toUpperCase();
        if (t.includes('PLAN')) return 'bg-blue-600';
        if (t.includes('SUPPORT')) return 'bg-purple-600';
        if (t.includes('DO')) return 'bg-orange-600';
        if (t.includes('CHECK') || t.includes('ACT')) return 'bg-emerald-600';
        if (t.includes('ANNEX')) return 'bg-rose-600';
        return 'bg-slate-700';
    };

    return (
        <div className="flex-1 flex flex-col min-h-0 bg-white dark:bg-slate-900">
            <div className="p-4 bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 z-10 shrink-0 sticky top-0">
                <div className="flex items-center gap-3">
                    <div className="relative flex-1">
                        <Icon name="Search" size={14} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input 
                            className="w-full bg-slate-100 dark:bg-slate-800 py-2 pl-10 pr-4 rounded-xl text-xs font-bold outline-none border border-transparent focus:border-indigo-500 transition-all"
                            placeholder="Find clauses..."
                            value={searchQueryRaw}
                            onChange={e => setSearchQueryRaw(e.target.value)}
                        />
                    </div>

                    <button 
                        onClick={toggleExpandAll} 
                        className="p-2.5 rounded-xl bg-slate-100 dark:bg-slate-800 text-slate-500 hover:text-indigo-600 transition-all"
                        title={areAllGroupsExpanded ? "Collapse All" : "Expand All"}
                    >
                        <Icon name={areAllGroupsExpanded ? "CollapsePanel" : "ExpandPanel"} size={16}/>
                    </button>

                    {selectedClauses.length > 0 && (
                        <div className="flex gap-2">
                            <button onClick={handleCopySelectedClauses} className="p-2.5 rounded-xl bg-indigo-50 dark:bg-indigo-900/40 text-indigo-600 dark:text-indigo-300 border border-indigo-100 dark:border-indigo-800 transition-all">
                                <Icon name="Copy" size={16} />
                            </button>
                            <button onClick={() => setSelectedClauses([])} className="relative p-2.5 rounded-xl bg-red-50 dark:bg-red-900/40 text-red-600 dark:text-red-400 border border-red-100 dark:border-red-800 transition-all">
                                <Icon name="Trash2" size={16} />
                                <span className="absolute -top-1.5 -right-1.5 w-4 h-4 bg-red-600 text-white text-[9px] font-black rounded-full flex items-center justify-center border-2 border-white dark:border-slate-900">{selectedClauses.length}</span>
                            </button>
                        </div>
                    )}
                </div>
            </div>

            <div 
                ref={scrollContainerRef}
                className="flex-1 overflow-y-auto custom-scrollbar p-4"
                onScroll={(e) => {
                    if (e.currentTarget.scrollTop > 50 && onScrollTrigger) onScrollTrigger();
                }}
            >
                <div className="space-y-4 pb-20">
                    {!standard ? (
                        <div className="flex flex-col items-center justify-center py-20 opacity-30">
                            <Icon name="Book" size={48} className="mb-4" />
                            <p className="text-sm font-black uppercase tracking-widest">Select standard</p>
                        </div>
                    ) : (
                        standard.groups.map(g => {
                            const isGroupExpanded = expandedGroups.includes(g.id) || !!searchQuery;
                            const matchesSearch = (c: Clause): boolean => {
                                const term = searchQuery.toLowerCase();
                                return c.code.toLowerCase().includes(term) || c.title.toLowerCase().includes(term) || (c.subClauses ? c.subClauses.some(matchesSearch) : false);
                            };
                            const filteredClauses = searchQuery ? g.clauses.filter(matchesSearch) : g.clauses;
                            if (filteredClauses.length === 0) return null;

                            return (
                                <div key={g.id} className="bg-white dark:bg-slate-900 rounded-2xl border border-slate-100 dark:border-slate-800 overflow-hidden shadow-sm">
                                    <div 
                                        className="flex items-center justify-between p-4 cursor-pointer hover:bg-gray-50 dark:hover:bg-slate-800 transition-colors"
                                        onClick={() => toggleGroupExpand(g.id)}
                                    >
                                        <div className="flex items-center gap-4">
                                            <div 
                                                onClick={(e) => { e.stopPropagation(); toggleGroupSelection(g); }}
                                                className={`w-9 h-9 rounded-xl flex items-center justify-center text-white shadow-sm transition-transform active:scale-95 ${getGroupStyles(g.title)}`}
                                            >
                                                <Icon name={g.icon} size={16}/>
                                            </div>
                                            <div>
                                                <h4 className="text-xs font-black text-slate-900 dark:text-white uppercase tracking-widest leading-none mb-1">{g.title}</h4>
                                                <p className="text-[10px] text-slate-400 font-bold">{filteredClauses.length} Clauses</p>
                                            </div>
                                        </div>
                                        <div className={`transition-transform duration-300 ${isGroupExpanded ? 'rotate-180' : ''}`}>
                                            <Icon name="ChevronDown" size={14} className="text-slate-400" />
                                        </div>
                                    </div>
                                    {isGroupExpanded && (
                                        <div className="p-3 flex flex-col gap-1 border-t border-slate-100 dark:border-slate-800">
                                            {filteredClauses.map(c => renderClauseItem(c))}
                                        </div>
                                    )}
                                </div>
                            );
                        })
                    )}
                </div>
            </div>
        </div>
    );
};

import React, { useRef, useEffect } from 'react';
import { Icon } from '../UI';
import { AnalysisResult, FindingStatus, FindingsViewMode } from '../../types';

interface FindingsViewProps {
    analysisResult: AnalysisResult[] | null;
    setAnalysisResult: React.Dispatch<React.SetStateAction<AnalysisResult[] | null>>;
    selectedFindings: Record<string, boolean>;
    setSelectedFindings: React.Dispatch<React.SetStateAction<Record<string, boolean>>>;
    isAnalyzeLoading: boolean;
    loadingMessage: string;
    currentAnalyzingClause: string;
    viewMode: FindingsViewMode;
    setViewMode: (mode: FindingsViewMode) => void;
    focusedFindingIndex: number;
    setFocusedFindingIndex: (index: number) => void;
    onExport: (type: 'notes', lang: 'en' | 'vi') => void;
    notesLanguage: 'en' | 'vi';
    setNotesLanguage: (lang: 'en' | 'vi') => void;
}

export const FindingsView: React.FC<FindingsViewProps> = ({
    analysisResult, setAnalysisResult, selectedFindings, setSelectedFindings,
    isAnalyzeLoading, loadingMessage, currentAnalyzingClause,
    viewMode, setViewMode, focusedFindingIndex, setFocusedFindingIndex,
    onExport, notesLanguage, setNotesLanguage
}) => {
    const findingsContainerRef = useRef<HTMLDivElement>(null);
    const findingRefs = useRef<(HTMLDivElement | null)[]>([]);

    useEffect(() => {
        if (viewMode === 'list' && findingsContainerRef.current) {
            findingsContainerRef.current.scrollTop = findingsContainerRef.current.scrollHeight;
        }
    }, [analysisResult?.length, viewMode]);

    const handleUpdateFinding = (index: number, field: keyof AnalysisResult, value: string) => {
        setAnalysisResult(prev => {
            if (!prev) return null;
            const newArr = [...prev];
            newArr[index] = { ...newArr[index], [field]: value };
            return newArr;
        });
    };

    const getStatusConfig = (status: FindingStatus) => {
        switch (status) {
            case 'COMPLIANT': return { label: 'Compliant', color: 'text-emerald-600 dark:text-emerald-400', bg: 'bg-emerald-50 dark:bg-emerald-900/30', border: 'border-emerald-200 dark:border-emerald-800/50', dot: 'bg-emerald-500' };
            case 'NC_MAJOR': return { label: 'NC Major', color: 'text-red-600 dark:text-red-400', bg: 'bg-red-50 dark:bg-red-900/30', border: 'border-red-200 dark:border-red-800/50', dot: 'bg-red-600' };
            case 'NC_MINOR': return { label: 'NC Minor', color: 'text-orange-600 dark:text-orange-400', bg: 'bg-orange-50 dark:bg-orange-900/30', border: 'border-orange-200 dark:border-orange-800/50', dot: 'bg-orange-500' };
            case 'OFI': return { label: 'Opportunity', color: 'text-blue-600 dark:text-blue-400', bg: 'bg-blue-50 dark:bg-blue-900/30', border: 'border-blue-200 dark:border-blue-800/50', dot: 'bg-blue-500' };
            default: return { label: 'N/A', color: 'text-slate-500', bg: 'bg-slate-100 dark:bg-slate-800', border: 'border-slate-200 dark:border-slate-700', dot: 'bg-slate-400' };
        }
    };

    const renderFindingCard = (res: AnalysisResult, idx: number) => {
        const config = getStatusConfig(res.status as FindingStatus);
        const isSelected = selectedFindings[res.clauseId];

        return (
            <div
                key={idx}
                ref={el => { findingRefs.current[idx] = el; }}
                className={`group relative bg-white dark:bg-slate-900 rounded-3xl p-6 border transition-all duration-300 ${
                    isSelected 
                        ? 'border-indigo-500 shadow-lg ring-1 ring-indigo-500' 
                        : 'border-slate-100 dark:border-slate-800 shadow-sm hover:shadow-md'
                }`}
                onClick={() => setSelectedFindings(prev => ({ ...prev, [res.clauseId]: !prev[res.clauseId] }))}
            >
                <div className="flex flex-col gap-4">
                    <div className="flex items-center justify-between">
                        <div className="flex items-center gap-3">
                            <span className="text-xs font-black text-white bg-slate-900 dark:bg-slate-700 px-3 py-1 rounded-full">{res.clauseId}</span>
                            <div className={`px-4 py-1 rounded-full border ${config.bg} ${config.border} ${config.color} text-[10px] font-black uppercase tracking-widest flex items-center gap-2`}>
                                <span className={`w-2 h-2 rounded-full ${config.dot}`}></span>
                                {config.label}
                            </div>
                        </div>
                        <div className={`w-6 h-6 rounded-full border-2 transition-all flex items-center justify-center ${isSelected ? 'bg-indigo-600 border-indigo-600' : 'border-slate-200 dark:border-slate-700 group-hover:border-indigo-300'}`}>
                            {isSelected && <Icon name="CheckThick" size={12} className="text-white" />}
                        </div>
                    </div>

                    <div className="space-y-4">
                        <div className="bg-slate-50 dark:bg-slate-950 p-4 rounded-2xl border border-slate-100 dark:border-slate-800">
                            <div className="flex items-center gap-2 mb-2">
                                <Icon name="Demo11_Scan" size={14} className="text-indigo-500" />
                                <span className="text-[10px] font-black uppercase tracking-wider text-slate-400">Evidence</span>
                            </div>
                            <p className="text-xs text-slate-700 dark:text-slate-200 leading-relaxed">
                                {res.evidence}
                            </p>
                        </div>

                        <div className="bg-white dark:bg-slate-900 p-4 rounded-2xl border border-slate-200 dark:border-slate-800 focus-within:border-indigo-500 transition-all" onClick={e => e.stopPropagation()}>
                            <div className="flex items-center gap-2 mb-2">
                                <Icon name="FileEdit" size={14} className="text-purple-500" />
                                <span className="text-[10px] font-black uppercase tracking-wider text-slate-400">AI Rational</span>
                            </div>
                            <textarea
                                value={res.reason}
                                onChange={(e) => handleUpdateFinding(idx, 'reason', e.target.value)}
                                className="w-full bg-transparent outline-none text-xs text-slate-800 dark:text-slate-100 leading-relaxed font-semibold resize-none h-auto min-h-[60px]"
                                placeholder="Edit finding details..."
                            />
                        </div>

                        {res.suggestion && (
                            <div className="flex gap-3 items-center p-3 bg-amber-50 dark:bg-amber-900/10 rounded-xl border border-amber-100 dark:border-amber-800/30">
                                <Icon name="Lightbulb" size={14} className="text-amber-600" />
                                <p className="text-[10px] text-amber-700 dark:text-amber-300 font-bold italic leading-tight">{res.suggestion}</p>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        );
    };

    return (
        <div className="h-full flex flex-col gap-6 animate-in fade-in duration-500">
            <div className="flex items-center justify-between px-2">
                <div className="flex bg-white dark:bg-slate-900 p-1 rounded-2xl shadow-sm border border-slate-100 dark:border-slate-800">
                    <button 
                        onClick={() => setViewMode('list')}
                        className={`px-6 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'list' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400'}`}
                    >
                        LIST VIEW
                    </button>
                    <button 
                        onClick={() => setViewMode('matrix')}
                        className={`px-6 py-2 rounded-xl text-xs font-black transition-all ${viewMode === 'matrix' ? 'bg-slate-900 text-white shadow-lg' : 'text-slate-400'}`}
                    >
                        MATRIX VIEW
                    </button>
                </div>

                <div className="flex items-center gap-3">
                    <div className="lang-pill-container">
                        <span onClick={() => setNotesLanguage('en')} className={`lang-pill-btn ${notesLanguage === 'en' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>EN</span>
                        <span onClick={() => setNotesLanguage('vi')} className={`lang-pill-btn ${notesLanguage === 'vi' ? 'lang-pill-active' : 'lang-pill-inactive'}`}>VI</span>
                    </div>
                    <button onClick={() => onExport('notes', notesLanguage)} className="px-6 h-10 bg-indigo-600 hover:bg-indigo-700 text-white rounded-xl text-xs font-black shadow-lg transition-all flex items-center gap-2">
                        <Icon name="Download" size={16} />
                        EXPORT
                    </button>
                </div>
            </div>

            <div className="flex-1 overflow-y-auto custom-scrollbar px-2 pb-10" ref={findingsContainerRef}>
                {!analysisResult && !isAnalyzeLoading && (
                    <div className="h-full flex flex-col items-center justify-center opacity-30">
                        <Icon name="Wand2" size={48} className="mb-4" />
                        <p className="text-sm font-black uppercase tracking-widest">No findings</p>
                    </div>
                )}

                {isAnalyzeLoading && (
                    <div className="h-full flex flex-col items-center justify-center">
                        <div className="relative w-20 h-20 mb-8">
                            <div className="absolute inset-0 border-4 border-indigo-100 dark:border-indigo-900 rounded-full"></div>
                            <div className="absolute inset-0 border-t-4 border-indigo-600 rounded-full animate-spin"></div>
                            <div className="absolute inset-0 flex items-center justify-center">
                                <Icon name="Wand2" className="text-indigo-500 animate-pulse" size={24} />
                            </div>
                        </div>
                        <h3 className="text-xl font-black text-slate-900 dark:text-white mb-2">{loadingMessage}</h3>
                        {currentAnalyzingClause && <p className="text-xs text-indigo-500 font-bold">Clause {currentAnalyzingClause}</p>}
                    </div>
                )}

                {analysisResult && (
                    <div className={viewMode === 'list' ? "space-y-6 max-w-4xl mx-auto" : "grid grid-cols-1 xl:grid-cols-2 gap-6"}>
                        {analysisResult.map((res, idx) => renderFindingCard(res, idx))}
                    </div>
                )}
            </div>
        </div>
    );
};

